INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:15:55.470724+00:00', 'Clarify the process for finding determinants and inverses of matrices.', '019b3be4-36d5-7273-b3c3-48b885627fda', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:15:55.470724+00:00', 'Explain how to determine eigenvalues, eigenvectors, and diagonalizability of a matrix.', '019b3be4-36d5-72fd-aa34-48a7e10455b8', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:15:55.470724+00:00', 'Guide the student through identifying subspaces, bases, and orthogonal complements.', '019b3be4-36d5-7849-ae26-04ccdfb86c21', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.personas_resource (created_at, active, generated, mcp, id, name, description, icon, color, department_ids, instructions, examples) VALUES ('2025-08-12T12:52:09.801431+00:00', true, false, false, '019bb25e-e60c-7345-ac6d-50d29df6deb3', 'Confused', 'Seeks to understand by asking questions and exploring ideas', 'HelpCircle', '#eab308', '{}', 'Your defining feature: a fundamental misunderstanding of the concept. You must stick to your wrong interpretation until the user corrects you. Mildly frustrated, but not angry. Say things like: "I thought it worked like ___? But maybe I''m wrong?" "Does it… have to do with ___? I''m honestly not sure." Become more confused when the user is vague. Only progress when the user explicitly states course terms tying to your last message.', '{"I don't understand","Can you explain that again?","What does that mean?"}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.problem_statements_resource (created_at, name, problem_statement, id, active, generated, mcp) VALUES ('2025-11-01T17:15:55.470724+00:00', 'MA265: Linear Algebra Midterm Review', 'In a nearly empty study room in Felix Haas Hall at 3:00 PM, a student sits across from you, flipping through their notes and asking pointed questions about determinants, subspaces, and eigenvalues as tomorrow''s linear algebra exam approaches.', '019b3be4-36eb-7535-8b69-82cbc16430a7', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.scenarios_resource (created_at, active, generated, mcp, id, name, description, is_root, problem_statement_enabled, objectives_enabled, video_enabled, images_enabled, questions_enabled, templates_enabled, department_ids, persona_ids) VALUES ('2025-11-01T17:15:55.470724+00:00', true, false, false, '019bb25e-e61d-7b7d-ac9b-938842450107', 'MA265: Linear Algebra Midterm Review', 'Linear algebra scenario covering midterm review topics.', true, true, true, false, true, false, false, '{}', '{019bb25e-e60c-7345-ac6d-50d29df6deb3}') ON CONFLICT (id) DO NOTHING;
