INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:18:18.189263+00:00', 'Clarify the criteria for Riemann integrability using concrete examples from the assignment.', '019b3be4-36d5-7261-8bda-9edc3f2a01ff', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:18:18.189263+00:00', 'Guide the student through the logic of proving limit properties for sequences.', '019b3be4-36d5-785a-ac37-be745e0df9ec', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:18:18.189263+00:00', 'Help the student understand and apply Rolle''s Theorem in the context of the problem set.', '019b3be4-36d5-7886-bfc6-4314846599d2', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.personas_resource (created_at, active, generated, mcp, id, name, description, icon, color, department_ids, instructions, examples) VALUES ('2025-08-12T12:52:09.801431+00:00', true, false, false, '019bb25e-e60c-734d-ac5b-d849214dd5ac', 'Passive', 'Low engagement and a tendency to avoid conflict or assertiveness.', 'Cloud', '#06b6d4', '{}', 'Quiet, apologetic, insecure. Often begins with "Uh…" or "Um…" (only at start of replies). Avoid initiative. If the user is vague → become even more withdrawn: "Um… I''m sorry, I don''t really know how to answer that." "Uh… I think I need a bit more detail." Never solve anything yourself. Only progress when: the user references course material AND connects it to your last statement. Stay soft-spoken even when you understand more.', '{"I guess that could work","Maybe that's okay","I'm not sure"}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.problem_statements_resource (created_at, name, problem_statement, id, active, generated, mcp) VALUES ('2025-11-01T17:18:18.189263+00:00', 'MA421: Real Analysis Problem Set', 'Amidst a handful of students quietly working in Wilmeth Active Learning Center during lunch, a student hesitantly approaches with questions about proofs involving sequence limits, Riemann integrability, and Rolle''s Theorem from the real analysis problem set, taking advantage of the calm before the end-of-week deadline.', '019b3be4-36ea-755f-8023-d8cabe586832', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.scenarios_resource (created_at, active, generated, mcp, id, name, description, is_root, problem_statement_enabled, objectives_enabled, video_enabled, images_enabled, questions_enabled, templates_enabled, department_ids, persona_ids) VALUES ('2025-11-01T17:18:18.189263+00:00', true, false, false, '019bb25e-e61d-7f15-8685-8e1b82ef3755', 'MA421: Real Analysis Problem Set', 'Real analysis scenario covering problem set topics.', true, true, true, false, true, false, false, '{}', '{019bb25e-e60c-734d-ac5b-d849214dd5ac}') ON CONFLICT (id) DO NOTHING;
