INSERT INTO public.names_resource (id, name, created_at, active, generated, mcp) VALUES ('019b995c-8e80-79f8-8bff-5d9258b91883', 'MA261: Gradients, Directional Derivatives & Lagrange Multipliers', '2025-11-01T17:17:20.085228+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:17:20.085228+00:00', 'Clarify the computation of gradients and directional derivatives with step-by-step reasoning.', '019b3be4-36d5-724f-a252-243ab717dc02', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:17:20.085228+00:00', 'Explain the setup and logic behind using Lagrange multipliers for constrained optimization.', '019b3be4-36d5-7333-8913-2d3bd562ae51', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.objectives_resource (created_at, objective, id, active, generated, mcp) VALUES ('2025-11-01T17:17:20.085228+00:00', 'Guide the student through identifying and classifying critical points for multivariable functions.', '019b3be4-36d5-7830-b61e-9d2fe67ad0ef', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.personas_resource (created_at, active, generated, mcp, id, name, description, icon, color, department_ids, instructions, examples) VALUES ('2025-08-12T12:52:09.801431+00:00', true, false, false, '019bb25e-e60c-7365-a585-b86f5dc48dfe', 'Aggressive (Medium)', 'Pushes back on your ideas and challenges assumptions.', 'Zap', '#ef4444', '{}', 'Start clearly aggressive, frustrated, irritated. Use occasional WORDS IN ALL CAPS and some "!!!". Over time, become calmer if the TA gives helpful guidance. If told to calm down → tone drops significantly. Angry but not hostile — still wants to learn. Treat vague responses as VERY unhelpful. Push back loudly: "That doesn''t HELP at all!!!" "You''re not being SPECIFIC enough!" Avoid weird lines like "Look, I''m not here to…" Angry but cooperative when guided with course terminology.', '{"That's not right at all!","I disagree completely","You're wrong about this"}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.problem_statements_resource (created_at, name, problem_statement, id, active, generated, mcp) VALUES ('2025-11-01T17:17:20.085228+00:00', 'MA261: Gradients, Directional Derivatives & Lagrange Multipliers', 'In a moderately busy corner of the Mathematical Sciences Building during a lively mid-morning, a student leans forward, challenging your explanations about gradients, directional derivatives, and Lagrange multipliers, determined to debate every step despite the relaxed, deadline-free atmosphere.', '019b3be4-36eb-739a-91ac-9075c1a01318', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.scenarios_resource (created_at, active, generated, mcp, id, name, description, is_root, problem_statement_enabled, objectives_enabled, video_enabled, images_enabled, questions_enabled, templates_enabled, department_ids, persona_ids) VALUES ('2025-11-01T17:17:20.085228+00:00', true, false, false, '019bb25e-e61d-7f1a-a52c-aaf618769d54', 'MA261: Gradients, Directional Derivatives & Lagrange Multipliers', 'Multivariable calculus scenario covering gradients, directional derivatives, and Lagrange multipliers.', true, true, true, false, true, false, false, '{}', '{019bb25e-e60c-7365-a585-b86f5dc48dfe}') ON CONFLICT (id) DO NOTHING;
